            s_tIn[tz + 1][0][tx + 1] = tIn[c - nx];
        else if (x < nx && y < ny && z < nz)
            s_tIn[tz + 1][0][tx + 1] = tIn[c];
        else
            s_tIn[tz + 1][0][tx + 1] = 0.0f;
    }
    if (ty == BLOCK_Y - 1) {
        if (y < ny - 1 && x < nx && z < nz)
            s_tIn[tz + 1][BLOCK_Y + 1][tx + 1] = tIn[c + nx];
